// Łączy outputy VT reduction i TF reduction w jeden obiekt + liczy primary_verdict
let combined = {};
for (const item of $input.all()) {
    Object.assign(combined, item.json);
}

const vt = combined.virustotal || { no_data: true };
const tf = combined.threatfox || { no_data: true };

// VT level
let vtLevel = 'CLEAN';
const vtMal = vt.vt_malicious_count || 0;
if (vt.no_data) {
    vtLevel = 'NO_DATA';
} else if (vt.vt_is_big_player && vtMal < 3) {
    vtLevel = 'CLEAN';
} else if (vtMal === 0) {
    vtLevel = 'CLEAN';
} else if (vtMal >= 1 && vtMal <= 3) {
    vtLevel = 'LOW';
} else if (vtMal >= 4 && vtMal <= 9) {
    vtLevel = 'MEDIUM';
} else if (vtMal >= 10) {
    vtLevel = 'HIGH';
}

// TF level
let tfLevel = 'CLEAN';
const tfConf = tf.threatfox_max_confidence || 0;
if (tf.no_data) {
    tfLevel = 'NO_DATA';
} else if (tf.threatfox_active && tfConf >= 75) {
    tfLevel = 'HIGH';
} else if (tf.threatfox_active && tfConf >= 50) {
    tfLevel = 'MEDIUM';
} else if (tf.threatfox_active) {
    tfLevel = 'LOW';
}

const levelToScore = { 'NO_DATA': 1, 'CLEAN': 1, 'LOW': 2, 'MEDIUM': 3, 'HIGH': 4 };
const primaryScore = Math.max(levelToScore[vtLevel] || 1, levelToScore[tfLevel] || 1);
const primaryFlagged = (vtLevel !== 'CLEAN' && vtLevel !== 'NO_DATA')
                    || (tfLevel !== 'CLEAN' && tfLevel !== 'NO_DATA');
const insufficientData = (vtLevel === 'NO_DATA' && tfLevel === 'NO_DATA');

return {
    primary_verdict: {
        vt_level: vtLevel,
        tf_level: tfLevel,
        vt_malicious_count: vtMal,
        tf_max_confidence: tfConf,
        vt_is_big_player: !!vt.vt_is_big_player,
        primary_score: primaryScore,
        primary_flagged: primaryFlagged,
        insufficient_data: insufficientData
    },
    virustotal: vt,
    threatfox: tf
};

return {
  resource: $('Select rows from a table').first().json.observable_ip,
  type: 'FQDN',
  source_provider: 'Abuse_URLhaus', 
  scan_date: new Date().toISOString(),
  raw_data: $('Abuse.CH_URLHaus (cond)').item.json
};

// Wywoływany TYLKO gdy primary_flagged = true i URLhaus zwrócił dane.
// Dostaje na wejściu raw URLhaus response (po Insert doc URLHaus → przekazany dalej).
// MUSI dosięgnąć primary_verdict z poprzedniego "Compute primary verdict" przez referencję.

const item = $input.item.json;
const raw = item.raw_data || item; // zależnie skąd przychodzi; obsłużymy oba przypadki
const urls = (raw && raw.urls) || [];
const mongoId = item.id || null;

// Pobierz primary_verdict i pozostałe sekcje z wcześniejszego węzła
const pv = $('Compute primary verdict').item.json.primary_verdict;
const vtSection = $('Compute primary verdict').item.json.virustotal;
const tfSection = $('Compute primary verdict').item.json.threatfox;

// Brak danych z URLhaus
if (urls.length === 0 && !raw.urlhaus_reference) {
    return {
        primary_verdict: pv,
        virustotal: vtSection,
        threatfox: tfSection,
        urlhaus: {
            no_data: true,
            urlhaus_status: 'no_data',
            urlhaus_report: 'SOURCE: Abuse_URLhaus\nSTATUS: No data available.',
            mongo_id: mongoId
        }
    };
}

// Limit objętości — max 5 najnowszych online URL-i, reszta to tylko statystyka
const onlineUrls = urls.filter(u => u.url_status === 'online');
const onlineCount = onlineUrls.length;

const tagMap = {};
urls.flatMap(u => u.tags || []).forEach(tag => {
    const cleanTag = (tag || '').trim().toLowerCase();
    if (cleanTag) tagMap[cleanTag] = (tagMap[cleanTag] || 0) + 1;
});
const topTags = Object.entries(tagMap)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(e => `${e[0]} (${e[1]}x)`)
    .join(', ');

const criticalKeywords = ['c2', 'cobaltstrike', 'rat', 'ransomware', 'brute', 'infostealer', 'stealer', 'brat', 'emotet', 'qakbot', 'lokibot'];
const foundCritical = Object.keys(tagMap).filter(t => criticalKeywords.includes(t));
const urlhausRef = raw.urlhaus_reference || 'No reference link available';

let report = `SOURCE: Abuse_URLhaus (SUPPORTING CONTEXT)\n`;
report += `- Total URLs in DB: ${raw.url_count || urls.length}\n`;
report += `- Currently online: ${onlineCount}\n`;
report += `- Top tags: ${topTags || 'None'}\n`;
if (foundCritical.length > 0) {
    report += `- CRITICAL TAGS: ${foundCritical.join(', ').toUpperCase()}\n`;
}
report += `- Reference: ${urlhausRef}\n`;

// Wyznacz status — primary już flaguje (skoro tu jesteśmy), więc:
// - jeśli urlhaus ma online URL-e → active_corroborating (modifier +1)
// - jeśli tylko historyczne → historical_only (modifier 0)
let urlhausStatus = onlineCount > 0 ? 'active_corroborating' : 'historical_only';
if (onlineCount === 0) {
    report = `SOURCE: Abuse_URLhaus\n- Historical URLs only (none currently online)\n- Total in DB: ${raw.url_count || urls.length}\n- Reference: ${urlhausRef}\n`;
}

return {
    primary_verdict: pv,
    virustotal: vtSection,
    threatfox: tfSection,
    urlhaus: {
        no_data: false,
        urlhaus_status: urlhausStatus,
        urlhaus_report: report,
        is_active_threat: onlineCount > 0,
        online_count: onlineCount,
        total_count: raw.url_count || urls.length,
        critical_tags: foundCritical,
        has_critical_tags: foundCritical.length > 0,
        urlhaus_reference: urlhausRef,
        mongo_id: mongoId
    }
};

const pv = $('Compute primary verdict').item.json.primary_verdict;
const vt = $('Compute primary verdict').item.json.virustotal;
const tf = $('Compute primary verdict').item.json.threatfox;
return {
    primary_verdict: pv,
    virustotal: vt,
    threatfox: tf,
    urlhaus: {
        no_data: true,
        urlhaus_status: 'query_not_ok',
        urlhaus_report: 'SOURCE: Abuse_URLhaus\nSTATUS: Query returned non-ok status.',
        is_active_threat: false,
        online_count: 0,
        total_count: 0,
        critical_tags: [],
        has_critical_tags: false,
        mongo_id: null
    }
};

// Wywoływany gdy primary_flagged = false. Tworzy stub żeby final merge miał z czym pracować.
// NIE wywołujemy URLhaus API i NIE zapisujemy nic do MongoDB.
const pv = $json.primary_verdict;
const vt = $json.virustotal;
const tf = $json.threatfox;

return {
    primary_verdict: pv,
    virustotal: vt,
    threatfox: tf,
    urlhaus: {
        skipped: true,
        no_data: true,
        urlhaus_status: 'skipped_primary_clean',
        urlhaus_report: 'SOURCE: Abuse_URLhaus\nSTATUS: Skipped — primary sources did not flag this artifact (token-saving optimization).',
        is_active_threat: false,
        online_count: 0,
        total_count: 0,
        critical_tags: [],
        has_critical_tags: false,
        mongo_id: null
    }
};

// Łączy primary_verdict + virustotal + threatfox + urlhaus w finalny aggregated_report dla AI
let combined = {};
for (const item of $input.all()) {
    Object.assign(combined, item.json);
}

const pv = combined.primary_verdict || {};
const vt = combined.virustotal || { no_data: true };
const tf = combined.threatfox || { no_data: true };
const uh = combined.urlhaus || { no_data: true, urlhaus_status: 'no_data' };

// Wyznacz urlhaus_modifier na podstawie statusu
let urlhausModifier = 0;
const status = uh.urlhaus_status || 'no_data';
if (status === 'active_corroborating') urlhausModifier = 1;
// historical_only, skipped_primary_clean, no_data → 0

let suggestedScore = Math.min(5, (pv.primary_score || 1) + urlhausModifier);
if (pv.insufficient_data) suggestedScore = 1;

const aggregated_report =
    `═══════════════════════════════════════════\n` +
    `PRIMARY SOURCES (drive the verdict)\n` +
    `═══════════════════════════════════════════\n\n` +
    (vt.vt_report || 'SOURCE: VirusTotal\nSTATUS: No data.') + `\n\n` +
    (tf.threatfox_report || 'SOURCE: Abuse_ThreatFox\nSTATUS: No data.') + `\n\n` +
    `═══════════════════════════════════════════\n` +
    `SUPPORTING CONTEXT (URLhaus)\n` +
    `═══════════════════════════════════════════\n\n` +
    (uh.urlhaus_report || 'SOURCE: Abuse_URLhaus\nSTATUS: No data.') + `\n\n` +
    `═══════════════════════════════════════════\n` +
    `PRE-COMPUTED PRIMARY VERDICT\n` +
    `═══════════════════════════════════════════\n` +
    `- VirusTotal level: ${pv.vt_level} (malicious_count=${pv.vt_malicious_count}, big_player=${pv.vt_is_big_player})\n` +
    `- ThreatFox level: ${pv.tf_level} (max_confidence=${pv.tf_max_confidence})\n` +
    `- URLhaus status: ${status} (modifier: +${urlhausModifier})\n` +
    `- Suggested score (1-5): ${suggestedScore}\n` +
    (pv.insufficient_data ? `- WARNING: insufficient primary data\n` : '');

return {
    aggregated_report: aggregated_report,
    primary_verdict: pv,
    final: {
        suggested_score: suggestedScore,
        urlhaus_status: status,
        urlhaus_modifier: urlhausModifier
    },
    mongo_ids: {
        virustotal: vt.mongo_id || null,
        threatfox: tf.mongo_id || null,
        urlhaus: uh.mongo_id || null
    },
    virustotal: vt,
    threatfox: tf,
    urlhaus: uh
};

return {
  resource: $('If \'malicious\' or \'suspicious\'').item.json.data.id, 
  type: "IP",
  source_provider: "VirusTotal", 
  scan_date: new Date().toISOString(),
  raw_data: $('VirusTotal IP Scan').item.json.data 
};

// Get item from n8n input
const item = $input.item.json;

const mongoId = item.id || null;

// Target the correct path in your specific JSON
const attr = item.raw_data && item.raw_data.attributes ? item.raw_data.attributes : {};

// 1. Get Analysis Stats
const stats = attr.last_analysis_stats || {};
const malCount = stats.malicious || 0;
const susCount = stats.suspicious || 0;
const undCount = stats.undetected || 0;

// 2. Get Engines that flagged it (Malicious/Suspicious)
const results = attr.last_analysis_results || {};
const flaggedBy = [];

Object.keys(results).forEach(engine => {
    if (results[engine].category === 'malicious' || results[engine].category === 'suspicious') {
        flaggedBy.push(`${engine} (${results[engine].result})`);
    }
});

// 3. Network & Ownership
const asOwner = attr.as_owner || "Unknown Owner";
const network = attr.network || "Unknown Network";
const rdap = attr.rdap || {};
const ipRange = (rdap.start_address && rdap.end_address) 
    ? `${rdap.start_address} - ${rdap.end_address}` 
    : "Range not specified";

// 4. Build the report string
let report = `SOURCE: VirusTotal\n`;
report += `- Owner: ${asOwner}\n`;
report += `- Network: ${network}\n`;
report += `- IP Range: ${ipRange}\n`;
report += `- Stats: Malicious: ${malCount}, Suspicious: ${susCount}, Undetected: ${undCount}\n`;

if (flaggedBy.length > 0) {
    report += `- Flagged by: ${flaggedBy.join(', ')}\n`;
}

// 5. Check if it's a Big Player
const bigPlayers = ["github", "google", "microsoft", "amazon", "cloudflare"];
const isBigPlayer = bigPlayers.some(p => asOwner.toLowerCase().includes(p));

if (!item.raw_data || !item.raw_data.attributes) {
    return {
        "virustotal": {
            "no_data": true,
            "vt_report": "SOURCE: VirusTotal\nSTATUS: No data found for this resource.",
            "mongo_id": mongoId
        }
    };
}

return {
    "virustotal": {
        "no_data": false,
        "vt_report": report,
        "vt_stats": stats,
        "vt_owner": asOwner,
        "vt_is_big_player": isBigPlayer,
        "vt_malicious_count": malCount,
        "vt_scan_date": item.scan_date,
        "mongo_id": mongoId
    }
};

