return {
  resource: $('Select rows from a table').first().json.observable_ip,
  type: 'FQDN',
  source_provider: 'Abuse_ThreatFox', 
  scan_date: new Date().toISOString(),
  raw_data: $('Abuse.CH_ThreatFox request').item.json
};

const item = $input.item.json;
const raw = item.raw_data || {};
const dataList = raw.data || [];
const mongoId = item.id || null;

const malwareFamilies = [...new Set(dataList.map(d => d.malware_printable).filter(m => m))];
const threatTypes = [...new Set(dataList.map(d => d.threat_type).filter(t => t))];

const confidenceScores = dataList.map(d => d.confidence_level).filter(c => c !== undefined);
const avgConfidence = confidenceScores.length > 0 
    ? (confidenceScores.reduce((a, b) => a + b, 0) / confidenceScores.length).toFixed(0) 
    : 0;

const tagMap = {};
dataList.flatMap(d => d.tags || []).forEach(tag => {
    const cleanTag = tag.trim();
    tagMap[cleanTag] = (tagMap[cleanTag] || 0) + 1;
});
const topTags = Object.entries(tagMap)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(e => e[0])
    .join(', ');

const externalRef = dataList.length > 0 ? dataList[0].reference : "No reference available";

let report = `SOURCE: Abuse_ThreatFox\n`;
if (dataList.length === 0 || raw.query_status !== "ok") {
    report += "STATUS: No indicators found for this resource.";
} else {
    report += `- Detections Found: ${dataList.length}\n`;
    report += `- Malware Families: ${malwareFamilies.join(', ') || 'Unknown'}\n`;
    report += `- Threat Types: ${threatTypes.join(', ') || 'Unknown'}\n`;
    report += `- Average Confidence: ${avgConfidence}%\n`;
    report += `- Top Tags: ${topTags || 'None'}\n`;
    report += `- Reference: ${externalRef}\n`;
}

if (dataList.length === 0 || raw.query_status !== "ok") {
    return {
        "threatfox": {
            "no_data": true,
            "threatfox_report": "SOURCE: Abuse_ThreatFox\nSTATUS: No indicators found.",
            "mongo_id": mongoId
        }
    };
}

return {
    "threatfox": {
        "no_data": false,
        "threatfox_report": report,
        "threatfox_active": dataList.length > 0,
        "threatfox_max_confidence": Math.max(...confidenceScores, 0),
        "mongo_id": mongoId
    }
};

